const LOCAL_API  = "http://localhost:5000";
const HOSTED_API = "https://your-app.onrender.com"; // update when deployed

// Tries local first, falls back to hosted
const BASE = process.env.REACT_APP_API_URL || LOCAL_API;

export async function predictImage(file) {
  const form = new FormData();
  form.append("file", file);
  const res = await fetch(`${BASE}/predict`, { method: "POST", body: form });
  if (!res.ok) throw new Error(`Prediction failed: ${res.status}`);
  return res.json();
}

export async function fetchStats() {
  const res = await fetch(`${BASE}/stats`);
  if (!res.ok) throw new Error(`Stats fetch failed: ${res.status}`);
  return res.json();
}

export async function generateReport(predictionResult) {
  const res = await fetch("https://api.groq.com/openai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${process.env.REACT_APP_GROQ_API_KEY}`
    },
    body: JSON.stringify({
      model: "nvidia/nemotron-3.5-content-safety:free",
      messages: [{
        role: "user",
        content: `You are an urban cleanliness analyst. A CNN model analysed a street image:
- Classification: ${predictionResult.label}
- Confidence: ${(predictionResult.confidence * 100).toFixed(1)}%
- Uncertainty (MC Dropout std): ${predictionResult.uncertainty}
- Predictive entropy: ${predictionResult.entropy}
- Flagged as ambiguous: ${predictionResult.is_ambiguous}

Write a professional 4-sentence cleanliness report for a municipal authority covering: the verdict and confidence, what it implies about the street condition, a recommended action, and a reliability note based on uncertainty. No bullet points.`
      }],
      max_tokens: 300
    })
  });
  if (!res.ok) {
  const errText = await res.text();
  console.error("Groq Error:", errText);
  throw new Error(`Report failed: ${res.status}`);
}
  const data = await res.json();
  return data.choices[0].message.content;
}
